import React, { useState, useEffect, useRef } from "react";
import { supabase } from "../lib/supabase";
import { LOGO_B64 } from "../utils/logo";

const G = "#22c55e";
const G_DIM = "rgba(34,197,94,0.12)";
const G_BORDER = "rgba(34,197,94,0.25)";

/* ── Helpers ── */
function daysAgo(dateStr) {
  if (!dateStr) return null;
  const d = Math.floor((Date.now() - new Date(dateStr)) / 86400000);
  if (d === 0) return "Aujourd'hui";
  if (d === 1) return "Hier";
  return `Il y a ${d}j`;
}

function activityColor(lastSeen) {
  if (!lastSeen) return "#444";
  const d = Math.floor((Date.now() - new Date(lastSeen)) / 86400000);
  if (d <= 1) return G;
  if (d <= 3) return "#4ade80";
  if (d <= 7) return "#f97316";
  return "#ef4444";
}

function Avatar({ name, size = 40, active }) {
  const letter = (name || "?")[0].toUpperCase();
  return (
    <div style={{
      width: size, height: size, borderRadius: "50%", flexShrink: 0,
      background: active ? G_DIM : "rgba(255,255,255,0.04)",
      border: `2px solid ${active ? G_BORDER : "rgba(255,255,255,0.08)"}`,
      display: "flex", alignItems: "center", justifyContent: "center",
      fontWeight: 700, fontSize: size * 0.38, color: active ? G : "#666",
      fontFamily: "'Inter',sans-serif",
    }}>
      {letter}
    </div>
  );
}

/* ── Stat card ── */
function StatCard({ label, value, sub, accent, icon }) {
  return (
    <div style={{
      background: "#141414", border: `1px solid ${accent ? G_BORDER : "rgba(255,255,255,0.06)"}`,
      borderRadius: 14, padding: "18px 16px",
      display: "flex", flexDirection: "column", gap: 4,
    }}>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
        <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", color: "#555" }}>{label}</div>
        <span style={{ fontSize: 18 }}>{icon}</span>
      </div>
      <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 28, fontWeight: 700, color: accent ? G : "#f5f5f5", lineHeight: 1.1 }}>{value}</div>
      {sub && <div style={{ fontSize: 11, color: "#555", marginTop: 2 }}>{sub}</div>}
    </div>
  );
}

/* ── Activity bar ── */
function ActivityBar({ value, max, color }) {
  const pct = max > 0 ? Math.min((value / max) * 100, 100) : 0;
  return (
    <div style={{ height: 4, background: "rgba(255,255,255,0.06)", borderRadius: 2, overflow: "hidden", marginTop: 4 }}>
      <div style={{ height: "100%", width: `${pct}%`, background: color || G, borderRadius: 2, transition: "width 0.6s ease" }} />
    </div>
  );
}

/* ── Client detail panel ── */
function ClientPanel({ client, onClose, onUpload, onDelete }) {
  const fileRef = useRef();
  const prog = client.programmes?.find(p => p.is_active);
  const logs = client._logs || [];
  const weights = client._weights || [];
  const lastLog = logs[0];
  const lastWeight = weights[0];

  // Exercices loggés cette semaine
  const weekAgo = new Date(); weekAgo.setDate(weekAgo.getDate() - 7);
  const weekLogs = logs.filter(l => new Date(l.logged_at) >= weekAgo);

  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 200,
      background: "rgba(0,0,0,0.7)", backdropFilter: "blur(12px)",
      display: "flex", alignItems: "center", justifyContent: "center",
      padding: 20,
    }} onClick={onClose}>
      <div
        style={{
          background: "#141414", border: "1px solid rgba(255,255,255,0.1)",
          borderRadius: 20, padding: 28, width: "100%", maxWidth: 480,
          maxHeight: "90vh", overflowY: "auto",
          animation: "slideUp 0.25s ease",
        }}
        onClick={e => e.stopPropagation()}
      >
        <style>{`@keyframes slideUp{from{opacity:0;transform:translateY(12px)}to{opacity:1;transform:translateY(0)}}`}</style>

        {/* Header */}
        <div style={{ display: "flex", alignItems: "center", gap: 14, marginBottom: 24 }}>
          <Avatar name={client.full_name || client.email} size={52} active={!!prog} />
          <div style={{ flex: 1 }}>
            <div style={{ fontSize: 16, fontWeight: 700, color: "#f5f5f5" }}>{client.full_name || "—"}</div>
            <div style={{ fontSize: 12, color: "#555", marginTop: 2 }}>{client.email}</div>
          </div>
          <button onClick={onClose} style={{ background: "none", border: "1px solid rgba(255,255,255,0.08)", borderRadius: 8, width: 32, height: 32, color: "#666", fontSize: 18, cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>×</button>
        </div>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 20 }}>
          {[
            { l: "Séances", v: logs.length > 0 ? Math.ceil(logs.length / 3) : 0, icon: "💪" },
            { l: "Cette semaine", v: weekLogs.length, icon: "🔥" },
            { l: "Pesées", v: weights.length, icon: "⚖️" },
          ].map((s, i) => (
            <div key={i} style={{ background: "#1a1a1a", borderRadius: 10, padding: "10px 12px", textAlign: "center" }}>
              <div style={{ fontSize: 18 }}>{s.icon}</div>
              <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 18, fontWeight: 700, color: G, marginTop: 2 }}>{s.v}</div>
              <div style={{ fontSize: 9, color: "#555", textTransform: "uppercase", letterSpacing: "1px" }}>{s.l}</div>
            </div>
          ))}
        </div>

        {/* Programme actif */}
        <div style={{ marginBottom: 16 }}>
          <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "#444", marginBottom: 8 }}>Programme</div>
          {prog ? (
            <div style={{ background: "#1a1a1a", borderRadius: 10, padding: "12px 14px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div>
                <div style={{ fontSize: 13, fontWeight: 600, color: "#f5f5f5" }}>{prog.programme_name}</div>
                <div style={{ fontSize: 11, color: G, marginTop: 2 }}>✓ Actif · {new Date(prog.uploaded_at).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}</div>
              </div>
              <button
                onClick={() => { fileRef.current?.click(); }}
                style={{ fontSize: 10, fontWeight: 700, color: "#9ca3af", background: "none", border: "1px solid rgba(255,255,255,0.1)", borderRadius: 7, padding: "5px 10px", cursor: "pointer" }}
              >Mettre à jour</button>
            </div>
          ) : (
            <div style={{ background: "rgba(249,115,22,0.06)", border: "1px solid rgba(249,115,22,0.2)", borderRadius: 10, padding: "12px 14px" }}>
              <div style={{ fontSize: 12, color: "#f97316" }}>⚠ Aucun programme — upload requis</div>
              <button onClick={() => fileRef.current?.click()} style={{ marginTop: 8, fontSize: 11, fontWeight: 700, color: G, background: G_DIM, border: `1px solid ${G_BORDER}`, borderRadius: 7, padding: "6px 14px", cursor: "pointer", width: "100%" }}>
                ↑ Uploader le programme
              </button>
            </div>
          )}
        </div>

        {/* Dernière activité */}
        {lastLog && (
          <div style={{ marginBottom: 16 }}>
            <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "#444", marginBottom: 8 }}>Dernière activité</div>
            <div style={{ background: "#1a1a1a", borderRadius: 10, padding: "12px 14px" }}>
              <div style={{ fontSize: 12, color: "#f5f5f5" }}>{lastLog.ex_key?.split("__")[0] || "Exercice"}</div>
              <div style={{ fontSize: 11, color: "#555", marginTop: 2 }}>
                {lastLog.weight && `${lastLog.weight} kg · `}{new Date(lastLog.logged_at).toLocaleDateString("fr-FR", { weekday: "short", day: "2-digit", month: "short" })}
              </div>
            </div>
          </div>
        )}

        {/* Dernier poids */}
        {lastWeight && (
          <div style={{ marginBottom: 20 }}>
            <div style={{ fontSize: 9, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: "#444", marginBottom: 8 }}>Poids</div>
            <div style={{ background: "#1a1a1a", borderRadius: 10, padding: "12px 14px", display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div>
                <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 20, fontWeight: 700, color: G }}>{lastWeight.weight} kg</div>
                <div style={{ fontSize: 11, color: "#555" }}>{new Date(lastWeight.date).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}</div>
              </div>
              <div style={{ fontSize: 28 }}>⚖️</div>
            </div>
          </div>
        )}

        {/* Actions */}
        <div style={{ display: "flex", gap: 8 }}>
          <input ref={fileRef} type="file" accept=".html" style={{ display: "none" }}
            onChange={e => { const f = e.target.files?.[0]; if (f) { onUpload(client, f); e.target.value = ""; } }} />
          <button onClick={() => onDelete(client.id, client.email)} style={{
            flex: 1, padding: "10px", background: "none",
            border: "1px solid rgba(239,68,68,0.2)", borderRadius: 10,
            color: "#ef4444", fontSize: 11, fontWeight: 700, cursor: "pointer",
          }}>Supprimer le client</button>
          <button onClick={onClose} style={{
            flex: 2, padding: "10px",
            background: G, border: "none", borderRadius: 10,
            color: "#0d0d0d", fontSize: 12, fontWeight: 800, cursor: "pointer",
          }}>Fermer</button>
        </div>
      </div>
    </div>
  );
}

/* ══════════════════════════════════════════════
   COACH DASHBOARD PRINCIPAL
══════════════════════════════════════════════ */
export function CoachDashboard({ onExit }) {
  const [clients,    setClients]    = useState([]);
  const [loading,    setLoading]    = useState(true);
  const [uploading,  setUploading]  = useState(false);
  const [search,     setSearch]     = useState("");
  const [showAdd,    setShowAdd]    = useState(false);
  const [newEmail,   setNewEmail]   = useState("");
  const [newName,    setNewName]    = useState("");
  const [toast,      setToast]      = useState(null);
  const [selected,   setSelected]   = useState(null);
  const [filter,     setFilter]     = useState("all"); // all | active | noprog
  const fileRef = useRef();

  const showToast = (msg, type = "ok") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  /* ── Charger clients avec leurs logs et poids ── */
  const loadClients = async () => {
    setLoading(true);
    try {
      const { data: clientsData } = await supabase
        .from("clients")
        .select("*, programmes(id, programme_name, uploaded_at, is_active)")
        .order("created_at", { ascending: false });

      if (!clientsData) { setLoading(false); return; }

      // Pour chaque client, charger les 5 derniers logs et le dernier poids
      const enriched = await Promise.all(clientsData.map(async (c) => {
        const [{ data: logs }, { data: weights }] = await Promise.all([
          supabase.from("exercise_logs").select("*")
            .eq("client_id", c.id)
            .order("logged_at", { ascending: false })
            .limit(20),
          supabase.from("weight_logs").select("*")
            .eq("client_id", c.id)
            .order("date", { ascending: false })
            .limit(10),
        ]);
        // Dernière activité = log le plus récent
        const lastActivity = logs?.[0]?.logged_at || weights?.[0]?.date || null;
        return { ...c, _logs: logs || [], _weights: weights || [], _lastActivity: lastActivity };
      }));

      setClients(enriched);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { loadClients(); }, []);

  /* ── Ajouter client ── */
  const addClient = async () => {
    if (!newEmail) return;
    const { error } = await supabase.from("clients").insert({
      email: newEmail.trim().toLowerCase(),
      full_name: newName.trim() || null,
    });
    if (error) { showToast(error.code === "23505" ? "Email déjà utilisé" : error.message, "err"); return; }
    showToast(`✓ ${newEmail} ajouté !`);
    setNewEmail(""); setNewName(""); setShowAdd(false);
    loadClients();
  };

  /* ── Supprimer client ── */
  const deleteClient = async (id, email) => {
    if (!window.confirm(`Supprimer ${email} ? Toutes ses données seront perdues.`)) return;
    await supabase.from("clients").delete().eq("id", id);
    setSelected(null);
    showToast("Client supprimé");
    loadClients();
  };

  /* ── Upload programme ── */
  const uploadProg = async (client, file) => {
    setUploading(true);
    try {
      const html = await file.text();
      const m = html.match(/id="prog-name"[^>]*value="([^"]*)"/);
      const progName = m?.[1] || file.name.replace(".html", "");
      await supabase.from("programmes").update({ is_active: false }).eq("client_id", client.id);
      const { error } = await supabase.from("programmes").insert({
        client_id: client.id, html_content: html,
        programme_name: progName || "Programme",
        is_active: true,
        uploaded_by: (await supabase.auth.getUser()).data.user?.email,
      });
      if (error) throw error;
      showToast(`✓ Programme uploadé pour ${client.full_name || client.email}`);
      loadClients();
    } catch (e) {
      showToast(e.message, "err");
    } finally {
      setUploading(false);
      setSelected(null);
    }
  };

  /* ── Filtres et stats ── */
  const total       = clients.length;
  const withProg    = clients.filter(c => c.programmes?.some(p => p.is_active)).length;
  const activeToday = clients.filter(c => {
    if (!c._lastActivity) return false;
    return Math.floor((Date.now() - new Date(c._lastActivity)) / 86400000) <= 1;
  }).length;
  const activeWeek = clients.filter(c => {
    if (!c._lastActivity) return false;
    return Math.floor((Date.now() - new Date(c._lastActivity)) / 86400000) <= 7;
  }).length;

  const filtered = clients
    .filter(c => {
      const s = search.toLowerCase();
      if (s && !c.email.includes(s) && !(c.full_name || "").toLowerCase().includes(s)) return false;
      if (filter === "active") return c._lastActivity && Math.floor((Date.now() - new Date(c._lastActivity)) / 86400000) <= 7;
      if (filter === "noprog") return !c.programmes?.some(p => p.is_active);
      return true;
    })
    .sort((a, b) => {
      // Trier par dernière activité
      if (!a._lastActivity && !b._lastActivity) return 0;
      if (!a._lastActivity) return 1;
      if (!b._lastActivity) return -1;
      return new Date(b._lastActivity) - new Date(a._lastActivity);
    });

  const inp = {
    padding: "10px 13px", background: "#141414",
    border: "1.5px solid rgba(255,255,255,0.08)", borderRadius: 9,
    color: "#f5f5f5", fontFamily: "'Inter',sans-serif", fontSize: 13, outline: "none",
    width: "100%", boxSizing: "border-box",
    transition: "border-color 0.15s",
  };

  return (
    <div style={{ minHeight: "100vh", background: "#0d0d0d", fontFamily: "'Inter',sans-serif", color: "#f5f5f5" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');
        @keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
        @keyframes spin{to{transform:rotate(360deg)}}
        .client-row:hover{background:#1c1c1c!important;cursor:pointer}
        .client-row:hover .row-arrow{opacity:1!important}
        .inp-focus:focus{border-color:#22c55e!important}
        ::-webkit-scrollbar{width:4px} ::-webkit-scrollbar-thumb{background:#333;border-radius:2px}
      `}</style>

      {/* Toast */}
      {toast && (
        <div style={{
          position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)",
          background: toast.type === "err" ? "#1a0a0a" : "#0a1a0f",
          border: `1px solid ${toast.type === "err" ? "rgba(239,68,68,0.3)" : G_BORDER}`,
          borderRadius: 10, padding: "10px 20px", fontSize: 12, fontWeight: 600,
          color: toast.type === "err" ? "#ef4444" : G, zIndex: 500,
          boxShadow: "0 8px 32px rgba(0,0,0,0.5)", whiteSpace: "nowrap",
          animation: "fadeUp 0.2s ease",
        }}>{toast.msg}</div>
      )}

      {/* Upload spinner overlay */}
      {uploading && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)", backdropFilter: "blur(8px)", zIndex: 300, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 14 }}>
          <div style={{ width: 44, height: 44, border: `3px solid #1a1a1a`, borderTopColor: G, borderRadius: "50%", animation: "spin 0.8s linear infinite" }} />
          <div style={{ color: G, fontSize: 13, fontWeight: 600 }}>Upload en cours...</div>
        </div>
      )}

      {/* Panel client sélectionné */}
      {selected && (
        <ClientPanel
          client={selected}
          onClose={() => setSelected(null)}
          onUpload={uploadProg}
          onDelete={deleteClient}
        />
      )}

      {/* Input file caché pour upload direct */}
      <input ref={fileRef} type="file" accept=".html" style={{ display: "none" }}
        onChange={e => {
          const f = e.target.files?.[0];
          if (f && selected) { uploadProg(selected, f); e.target.value = ""; }
        }}
      />

      {/* ─── TOPBAR ─── */}
      <div style={{
        background: "rgba(13,13,13,0.97)", borderBottom: "1px solid rgba(255,255,255,0.07)",
        padding: "0 32px", height: 60, display: "flex", alignItems: "center",
        justifyContent: "space-between", position: "sticky", top: 0, zIndex: 100,
        backdropFilter: "blur(20px)",
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
          <div style={{ width: 32, height: 32, borderRadius: 8, overflow: "hidden", border: "1px solid rgba(255,255,255,0.1)" }}>
            <img src={LOGO_B64} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
          </div>
          <div>
            <span style={{ fontSize: 14, fontWeight: 800, color: "#f5f5f5" }}>RB <span style={{ color: G }}>Performance</span></span>
            <span style={{ fontSize: 10, fontWeight: 700, color: "#333", letterSpacing: "2px", marginLeft: 8 }}>COACH</span>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <button onClick={loadClients} style={{
            background: "none", border: "1px solid rgba(255,255,255,0.08)",
            borderRadius: 7, padding: "5px 12px", color: "#555",
            fontSize: 11, fontWeight: 600, cursor: "pointer",
          }}>↻ Actualiser</button>
          <button onClick={onExit} style={{
            background: "none", border: "1px solid rgba(255,255,255,0.08)",
            borderRadius: 7, padding: "5px 12px", color: "#555",
            fontSize: 11, fontWeight: 600, cursor: "pointer",
          }}>← Mon app</button>
        </div>
      </div>

      <div style={{ maxWidth: 1100, margin: "0 auto", padding: "32px 24px 60px" }}>

        {/* ─── TITRE ─── */}
        <div style={{ marginBottom: 28 }}>
          <h1 style={{ fontSize: 26, fontWeight: 800, letterSpacing: "-0.5px", color: "#f5f5f5", marginBottom: 4 }}>
            Dashboard Coach
          </h1>
          <p style={{ fontSize: 13, color: "#555" }}>
            Vue d'ensemble de tes {total} client{total > 1 ? "s" : ""}
          </p>
        </div>

        {/* ─── STATS CARDS ─── */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 12, marginBottom: 28 }}>
          <StatCard label="Clients total" value={total} icon="👥" />
          <StatCard label="Avec programme" value={withProg} sub={`${total - withProg} sans programme`} icon="📋" />
          <StatCard label="Actifs aujourd'hui" value={activeToday} accent={activeToday > 0} icon="🔥" />
          <StatCard label="Actifs cette semaine" value={activeWeek} accent={activeWeek > 0} sub={`${total - activeWeek} inactifs`} icon="📈" />
        </div>

        {/* ─── ACTIONS + FILTRES ─── */}
        <div style={{ display: "flex", gap: 10, marginBottom: 16, alignItems: "center", flexWrap: "wrap" }}>
          <input
            className="inp-focus"
            placeholder="🔍  Rechercher un client..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{ ...inp, flex: 1, minWidth: 200 }}
          />

          {/* Filtres */}
          <div style={{ display: "flex", gap: 4 }}>
            {[["all", "Tous", total], ["active", "Actifs 7j", activeWeek], ["noprog", "Sans programme", total - withProg]].map(([k, l, n]) => (
              <button key={k} onClick={() => setFilter(k)} style={{
                padding: "8px 14px", fontSize: 11, fontWeight: 600,
                background: filter === k ? G_DIM : "transparent",
                border: `1px solid ${filter === k ? G_BORDER : "rgba(255,255,255,0.08)"}`,
                borderRadius: 100, color: filter === k ? G : "#666",
                cursor: "pointer", transition: "all 0.15s", whiteSpace: "nowrap",
              }}>
                {l} <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 10 }}>({n})</span>
              </button>
            ))}
          </div>

          <button onClick={() => setShowAdd(v => !v)} style={{
            display: "flex", alignItems: "center", gap: 6,
            padding: "9px 18px", background: showAdd ? G_DIM : G,
            border: `1px solid ${showAdd ? G_BORDER : G}`,
            borderRadius: 9, color: showAdd ? G : "#0d0d0d",
            fontSize: 12, fontWeight: 700, cursor: "pointer",
            boxShadow: showAdd ? "none" : "0 4px 16px rgba(34,197,94,0.25)",
          }}>
            {showAdd ? "✕ Annuler" : "+ Nouveau client"}
          </button>
        </div>

        {/* ─── FORMULAIRE NOUVEAU CLIENT ─── */}
        {showAdd && (
          <div style={{
            background: "#141414", border: `1px solid ${G_BORDER}`,
            borderRadius: 14, padding: 20, marginBottom: 16,
            animation: "fadeUp 0.2s ease",
          }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: "2px", textTransform: "uppercase", color: G, marginBottom: 14 }}>
              Nouveau client
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr auto", gap: 10 }}>
              <div>
                <label style={{ fontSize: 9, color: "#555", fontWeight: 700, letterSpacing: "1px", textTransform: "uppercase", display: "block", marginBottom: 4 }}>Email *</label>
                <input className="inp-focus" type="email" placeholder="client@email.com"
                  value={newEmail} onChange={e => setNewEmail(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && addClient()}
                  style={inp} />
              </div>
              <div>
                <label style={{ fontSize: 9, color: "#555", fontWeight: 700, letterSpacing: "1px", textTransform: "uppercase", display: "block", marginBottom: 4 }}>Prénom Nom</label>
                <input className="inp-focus" type="text" placeholder="Thomas Dupont"
                  value={newName} onChange={e => setNewName(e.target.value)}
                  onKeyDown={e => e.key === "Enter" && addClient()}
                  style={inp} />
              </div>
              <div style={{ display: "flex", alignItems: "flex-end" }}>
                <button onClick={addClient} disabled={!newEmail} style={{
                  padding: "10px 20px", background: newEmail ? G : "#1e1e1e",
                  border: "none", borderRadius: 9,
                  color: newEmail ? "#0d0d0d" : "#444",
                  fontSize: 12, fontWeight: 700,
                  cursor: newEmail ? "pointer" : "not-allowed",
                  height: 40,
                }}>Créer</button>
              </div>
            </div>
          </div>
        )}

        {/* ─── TABLE CLIENTS ─── */}
        {loading ? (
          <div style={{ textAlign: "center", padding: 60, color: "#555" }}>
            <div style={{ width: 32, height: 32, border: `2.5px solid #222`, borderTopColor: G, borderRadius: "50%", animation: "spin 0.8s linear infinite", margin: "0 auto 12px" }} />
            Chargement des clients...
          </div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: 60, color: "#444", fontSize: 13 }}>
            {search || filter !== "all" ? "Aucun client correspond aux filtres" : "Aucun client — ajoute ton premier client 👆"}
          </div>
        ) : (
          <div style={{ background: "#0f0f0f", border: "1px solid rgba(255,255,255,0.06)", borderRadius: 16, overflow: "hidden" }}>
            {/* Header de colonne */}
            <div style={{
              display: "grid", gridTemplateColumns: "2fr 1.5fr 1fr 1fr 1fr 1fr auto",
              padding: "10px 20px", borderBottom: "1px solid rgba(255,255,255,0.05)",
              fontSize: 9, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", color: "#444",
            }}>
              <div>Client</div>
              <div>Programme</div>
              <div>Activité</div>
              <div>Séances</div>
              <div>Poids</div>
              <div>Dernier contact</div>
              <div></div>
            </div>

            {/* Lignes clients */}
            {filtered.map((c, i) => {
              const prog = c.programmes?.find(p => p.is_active);
              const hasProg = !!prog;
              const lastAct = c._lastActivity;
              const actColor = activityColor(lastAct);
              const logsCount = Math.ceil(c._logs.length / 3);
              const lastWeight = c._weights?.[0];
              const daysAgoStr = daysAgo(lastAct);

              return (
                <div
                  key={c.id}
                  className="client-row"
                  style={{
                    display: "grid", gridTemplateColumns: "2fr 1.5fr 1fr 1fr 1fr 1fr auto",
                    padding: "14px 20px",
                    borderBottom: i < filtered.length - 1 ? "1px solid rgba(255,255,255,0.04)" : "none",
                    alignItems: "center", gap: 8,
                    transition: "background 0.15s",
                    animation: `fadeUp ${0.1 + i * 0.03}s ease both`,
                  }}
                  onClick={() => setSelected(c)}
                >
                  {/* Nom */}
                  <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                    <Avatar name={c.full_name || c.email} size={36} active={hasProg} />
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 600, color: "#f5f5f5" }}>
                        {c.full_name || <span style={{ color: "#555" }}>Sans nom</span>}
                      </div>
                      <div style={{ fontSize: 11, color: "#555" }}>{c.email}</div>
                    </div>
                  </div>

                  {/* Programme */}
                  <div>
                    {hasProg ? (
                      <>
                        <div style={{ fontSize: 11, fontWeight: 600, color: G }}>✓ {prog.programme_name || "Programme actif"}</div>
                        <div style={{ fontSize: 10, color: "#444" }}>{new Date(prog.uploaded_at).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}</div>
                      </>
                    ) : (
                      <span style={{ fontSize: 11, color: "#f97316", fontWeight: 600 }}>⚠ Aucun programme</span>
                    )}
                  </div>

                  {/* Activité */}
                  <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                    <div style={{ width: 7, height: 7, borderRadius: "50%", background: actColor, boxShadow: lastAct && Math.floor((Date.now() - new Date(lastAct)) / 86400000) <= 1 ? `0 0 6px ${actColor}` : "none" }} />
                    <span style={{ fontSize: 10, color: actColor, fontWeight: 600 }}>
                      {lastAct ? (Math.floor((Date.now() - new Date(lastAct)) / 86400000) <= 1 ? "Actif" : Math.floor((Date.now() - new Date(lastAct)) / 86400000) <= 7 ? "Cette semaine" : "Inactif") : "Jamais"}
                    </span>
                  </div>

                  {/* Séances loggées */}
                  <div>
                    <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 15, fontWeight: 600, color: logsCount > 0 ? "#f5f5f5" : "#444" }}>{logsCount}</div>
                    <ActivityBar value={logsCount} max={20} color={logsCount > 0 ? G : "#333"} />
                  </div>

                  {/* Poids */}
                  <div>
                    {lastWeight ? (
                      <>
                        <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 15, fontWeight: 600, color: "#f5f5f5" }}>{lastWeight.weight} kg</div>
                        <div style={{ fontSize: 10, color: "#444" }}>{new Date(lastWeight.date).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}</div>
                      </>
                    ) : (
                      <span style={{ fontSize: 11, color: "#444" }}>—</span>
                    )}
                  </div>

                  {/* Dernier contact */}
                  <div style={{ fontSize: 11, color: daysAgoStr ? (daysAgoStr === "Aujourd'hui" || daysAgoStr === "Hier" ? G : "#9ca3af") : "#444" }}>
                    {daysAgoStr || "Jamais"}
                  </div>

                  {/* Flèche */}
                  <div className="row-arrow" style={{ opacity: 0, transition: "opacity 0.15s", color: "#555", fontSize: 14 }}>→</div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
}
